import { useCallback, useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { UserInfo, InterestTab, InterestTag } from "@sitin/api-proto/gen/archat_api/user_api";
import { Post } from "@sitin/api-proto/gen/archat_api/post_api";
import { getUserBasicInfos } from "@/http/chatApi";
import { getPostsByUserId } from "@/http/postApi";
import { getAvatarUrl, CustomAvatarType, DEFAULT_AVATAR } from "@/utils/userUtil";
import Spinner from "@/components/Spinner";
import Avatar from "@/components/Avatar";
import DetailItems from "@/components/DetailItems";
import PostList from "@/pages/Me/PostList";
import icBackWhite from "@/assets/images/common/ic_back_white.svg";

export default function Profile() {
  const { userId } = (useLocation().state as { userId?: number }) ?? {};
  const navigate = useNavigate();
  const [userInfo, setUserInfo] = useState<UserInfo | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const cursorRef = useRef(0);

  useEffect(() => {
    if (!userId) {
      navigate(-1);
      return;
    }
    getUserBasicInfos([userId])
      .then((resp) => {
        const info = resp?.userBasicInfos?.[0];
        if (info) setUserInfo(info);
      })
      .catch(() => {});
  }, [userId, navigate]);

  const fetchPosts = useCallback(
    async (refresh = false) => {
      if (!userInfo) return;
      if (refresh) {
        cursorRef.current = 0;
        setHasMore(true);
      }
      if (!refresh && !hasMore) return;

      setIsLoading(true);
      try {
        const resp = await getPostsByUserId({ userId: userInfo.userId, cursor: refresh ? 0 : cursorRef.current });
        const newPosts = resp.posts ?? [];
        setPosts(refresh ? newPosts : (prev) => [...prev, ...newPosts]);
        cursorRef.current = resp.nextCursor ?? 0;
        setHasMore(newPosts.length > 0 && (resp.nextCursor ?? 0) > 0);
      } catch {
        // ignore
      } finally {
        setIsLoading(false);
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [userInfo, hasMore],
  );

  useEffect(() => {
    if (userInfo) fetchPosts(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [userInfo?.userId]);

  if (!userInfo)
    return (
      <div className="flex h-full w-full items-center justify-center bg-surface">
        <Spinner />
      </div>
    );

  const avatarUrl = getAvatarUrl(userInfo, CustomAvatarType.Mid);
  const interests =
    userInfo.interestTabs
      ?.flatMap((tab: InterestTab) => tab.tags?.map((tag: InterestTag) => tag.key))
      ?.filter((k): k is string => !!k && k !== "None")
      ?.slice(0, 3) ?? [];

  return (
    <div className="flex h-full w-full flex-col overflow-y-auto bg-surface animate-fade-in">
      <div
        className="flex min-h-[290px] w-full shrink-0 flex-col bg-cover bg-center bg-no-repeat px-4 pt-[calc(var(--sat,0px)+24px)] pb-6 gap-4"
        style={{
          backgroundImage: `linear-gradient(rgba(0,0,0,0.2), rgba(0,0,0,0.5)), url('${avatarUrl || DEFAULT_AVATAR}')`,
        }}
      >
        <button type="button" className="self-start border-none bg-transparent" onClick={() => navigate(-1)}>
          <img
            src={icBackWhite}
            className="h-6 w-6"
            alt="back"
            style={{ filter: "drop-shadow(0px 1px 2px rgba(0,0,0,0.5))" }}
          />
        </button>
        <div className="flex flex-col gap-5 mt-6">
          <div className="flex items-center gap-4">
            <Avatar
              src={avatarUrl}
              className="h-[83px] w-[83px] border-2 border-white shadow-[0_2px_8px_rgba(0,0,0,0.3)]"
            />
            <h1
              className="flex-1 text-[24px] font-bold leading-[1.2] text-white"
              style={{ textShadow: "0 1px 3px rgba(0,0,0,0.8)" }}
            >
              {userInfo.username || "N/A"}
              {userInfo.age && (
                <>
                  <span className="mx-[5px] font-normal">•</span>
                  {userInfo.age}
                </>
              )}
            </h1>
          </div>
          <DetailItems
            hometown={userInfo.geoLocation?.city}
            profession={userInfo.profession}
            bio={userInfo.bio}
            tags={interests}
          />
        </div>
      </div>
      <div className="flex-1 w-full">
        <PostList posts={posts} isLoading={isLoading} hasMore={hasMore} onLoadMore={fetchPosts} />
      </div>
    </div>
  );
}
